"use client";

import { useState, useEffect } from "react";
import { AlertTriangle, HelpCircle, Plus, X, Check, Ban } from "lucide-react";
import { cn } from "@/lib/utils";
import { DecisionBadge } from "@/components/ui/decision-badge";
import { Button } from "@/components/ui/button";
import type { StoredProject } from "@/hooks/use-project";

interface DiscoveryWorkspaceProps {
    project: StoredProject;
}

interface Hypothesis {
    id: string;
    text: string;
    status: "to_validate" | "validated" | "invalidated";
}

interface ExplorationQuestion {
    axis: string;
    question: string;
    context: string;
    severity: "HIGH" | "MEDIUM" | "LOW";
}

const AXIS_KEYS = ["problem", "market", "differentiation", "feasibility", "business", "founder_fit"] as const;

function generateQuestions(project: StoredProject): ExplorationQuestion[] {
    const questions: ExplorationQuestion[] = [];

    if (project.fullResult) {
        const { analysis, risks } = project.fullResult;

        // Questions from weak axes (score < 60)
        for (const key of AXIS_KEYS) {
            const axis = analysis[key];
            if (axis.score < 60) {
                const label = key.charAt(0).toUpperCase() + key.slice(1).replace("_", " ");
                const severity = axis.score < 40 ? "HIGH" : "MEDIUM";

                if (key === "problem") {
                    questions.push({
                        axis: label,
                        question: "Avez-vous interviewe au moins 10 utilisateurs potentiels pour valider ce probleme ?",
                        context: axis.justification,
                        severity,
                    });
                } else if (key === "market") {
                    questions.push({
                        axis: label,
                        question: "Quelle est la taille reelle de votre marche adressable (TAM/SAM/SOM) ?",
                        context: axis.justification,
                        severity,
                    });
                } else if (key === "differentiation") {
                    questions.push({
                        axis: label,
                        question: "Qu'est-ce qui empeche un concurrent de reproduire votre solution en 6 mois ?",
                        context: axis.justification,
                        severity,
                    });
                } else if (key === "feasibility") {
                    questions.push({
                        axis: label,
                        question: "Avez-vous un prototype ou POC fonctionnel ? Quels sont les risques techniques principaux ?",
                        context: axis.justification,
                        severity,
                    });
                } else if (key === "business") {
                    questions.push({
                        axis: label,
                        question: "Quel est votre modele de revenus ? Avez-vous valide la willingness-to-pay aupres de prospects ?",
                        context: axis.justification,
                        severity,
                    });
                } else if (key === "founder_fit") {
                    questions.push({
                        axis: label,
                        question: "Quelle experience specifique avez-vous dans ce domaine ? Quelles competences manquent a l'equipe ?",
                        context: axis.justification,
                        severity,
                    });
                }
            }
        }

        // Questions from risks
        for (const risk of risks) {
            if (risk.severity === "HIGH") {
                const label = risk.axis.charAt(0).toUpperCase() + risk.axis.slice(1).replace("_", " ");
                questions.push({
                    axis: label,
                    question: `Comment comptez-vous mitiger ce risque : "${risk.description}" ?`,
                    context: risk.description,
                    severity: "HIGH",
                });
            }
        }
    } else {
        // Fallback for projects without fullResult
        for (const axis of project.analysis.axes) {
            const score = axis.score <= 10 ? axis.score * 10 : axis.score;
            if (score < 60) {
                questions.push({
                    axis: axis.label,
                    question: `L'axe "${axis.label}" est faible (${score}/100). Quelles actions concretes envisagez-vous ?`,
                    context: axis.justification || "Score insuffisant",
                    severity: score < 40 ? "HIGH" : "MEDIUM",
                });
            }
        }
    }

    return questions;
}

export function DiscoveryWorkspace({ project }: DiscoveryWorkspaceProps) {
    const storageKey = `k3rn_lab1_hypotheses_${project.id}`;
    const [hypotheses, setHypotheses] = useState<Hypothesis[]>([]);
    const [newHypothesis, setNewHypothesis] = useState("");
    const [showInput, setShowInput] = useState(false);

    const questions = generateQuestions(project);

    // Load hypotheses from localStorage
    useEffect(() => {
        const stored = localStorage.getItem(storageKey);
        if (stored) {
            try {
                setHypotheses(JSON.parse(stored));
            } catch { /* ignore */ }
        }
    }, [storageKey]);

    // Save hypotheses to localStorage
    useEffect(() => {
        localStorage.setItem(storageKey, JSON.stringify(hypotheses));
    }, [hypotheses, storageKey]);

    function addHypothesis() {
        if (!newHypothesis.trim()) return;
        setHypotheses([
            ...hypotheses,
            { id: crypto.randomUUID(), text: newHypothesis.trim(), status: "to_validate" },
        ]);
        setNewHypothesis("");
        setShowInput(false);
    }

    function updateStatus(id: string, status: Hypothesis["status"]) {
        setHypotheses(hypotheses.map((h) => (h.id === id ? { ...h, status } : h)));
    }

    function removeHypothesis(id: string) {
        setHypotheses(hypotheses.filter((h) => h.id !== id));
    }

    return (
        <main className="flex-1 overflow-y-auto bg-[#22242B] p-8">
            <div className="max-w-3xl mx-auto space-y-10">

                {/* Verdict Section */}
                <section>
                    <div className="flex items-center gap-4 mb-4">
                        <DecisionBadge decision={project.recommendation} />
                        <span className={cn(
                            "text-3xl font-bold tracking-tight",
                            project.globalScore >= 70 ? "text-white" : "text-gray-400"
                        )}>
                            {project.globalScore}/100
                        </span>
                    </div>
                    {project.analysis.synthesis && (
                        <blockquote className="pl-4 border-l-2 border-[#F75105]/50 text-sm text-gray-300 leading-relaxed italic">
                            &ldquo;{project.analysis.synthesis}&rdquo;
                        </blockquote>
                    )}
                </section>

                {/* Questions to Explore */}
                {questions.length > 0 && (
                    <section>
                        <h2 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4 flex items-center gap-2">
                            <HelpCircle className="w-3.5 h-3.5 text-[#F75105]" />
                            Questions a Explorer
                        </h2>
                        <div className="space-y-3">
                            {questions.map((q, i) => (
                                <div
                                    key={i}
                                    className={cn(
                                        "p-4 rounded-xl border bg-[#2F323A]",
                                        q.severity === "HIGH" ? "border-red-500/30" :
                                        q.severity === "MEDIUM" ? "border-amber-500/20" :
                                        "border-white/5"
                                    )}
                                >
                                    <div className="flex items-center gap-2 mb-2">
                                        <span className="text-[10px] font-bold uppercase tracking-wider text-[#F75105] bg-[#F75105]/10 px-2 py-0.5 rounded">
                                            {q.axis}
                                        </span>
                                        <span className={cn(
                                            "text-[9px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded",
                                            q.severity === "HIGH" ? "bg-red-500/10 text-red-400" :
                                            q.severity === "MEDIUM" ? "bg-amber-500/10 text-amber-400" :
                                            "bg-gray-500/10 text-gray-400"
                                        )}>
                                            {q.severity}
                                        </span>
                                    </div>
                                    <p className="text-sm text-white mb-2">{q.question}</p>
                                    <p className="text-[11px] text-gray-500 leading-relaxed">{q.context}</p>
                                </div>
                            ))}
                        </div>
                    </section>
                )}

                {/* Hypotheses to Validate */}
                <section>
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-xs text-gray-500 uppercase tracking-widest font-bold flex items-center gap-2">
                            <AlertTriangle className="w-3.5 h-3.5 text-amber-400" />
                            Hypotheses a Valider
                        </h2>
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setShowInput(true)}
                            className="text-[#F75105] hover:text-[#F78E21] hover:bg-[#F75105]/10 text-xs"
                        >
                            <Plus className="w-3.5 h-3.5 mr-1" />
                            Ajouter
                        </Button>
                    </div>

                    {showInput && (
                        <div className="mb-4 flex gap-2">
                            <input
                                type="text"
                                value={newHypothesis}
                                onChange={(e) => setNewHypothesis(e.target.value)}
                                onKeyDown={(e) => e.key === "Enter" && addHypothesis()}
                                placeholder="Ex: Les PME sont pretes a payer 50€/mois pour cette solution..."
                                className="flex-1 px-3 py-2 bg-[#2F323A] border border-white/10 rounded-lg text-sm text-white placeholder:text-gray-500 focus:outline-none focus:border-[#F75105]/50"
                                autoFocus
                            />
                            <Button onClick={addHypothesis} size="sm" className="bg-[#F75105] hover:bg-[#F78E21] text-white">
                                OK
                            </Button>
                            <Button onClick={() => { setShowInput(false); setNewHypothesis(""); }} variant="ghost" size="sm" className="text-gray-400">
                                <X className="w-4 h-4" />
