            try {
                setIsLoading(true);
                const response = await fetch(`/api/projects/${project.id}/cards?type=NOTE&phase=IDEATION`);
                if (response.ok) {
                    const data = await response.json();
                    const cards: Card[] = data.data || [];
                    setHypotheses(cards.map(cardToHypothesis));
                }
            } catch (error) {
                console.error("Failed to load hypotheses:", error);
            } finally {
                setIsLoading(false);
            }
        }
        loadHypotheses();
    }, [project.id]);

    async function addHypothesis() {
        if (!newHypothesis.trim()) return;
        try {
            const response = await fetch(`/api/projects/${project.id}/cards`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    type: "NOTE",
                    label: newHypothesis.trim(),
                    phase: "IDEATION",
                    status: "DRAFT",
                    priority: "MEDIUM",
                    metadata: { invalidated: false }
                })
            });

            if (response.ok) {
                const data = await response.json();
                const newCard: Card = data.data;
                setHypotheses([...hypotheses, cardToHypothesis(newCard)]);
                setNewHypothesis("");
                setShowInput(false);
            }
        } catch (error) {
            console.error("Failed to add hypothesis:", error);
        }
    }

    async function updateStatus(id: string, status: Hypothesis["status"]) {
        try {
            const validated = status === "validated";
            const invalidated = status === "invalidated";

            const response = await fetch(`/api/cards/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    validated,
                    metadata: { invalidated }
                })
            });

            if (response.ok) {
                setHypotheses(hypotheses.map((h) => (h.id === id ? { ...h, status } : h)));
            }
        } catch (error) {
            console.error("Failed to update hypothesis:", error);
        }
    }
